// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // Wire hooks — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit');

  // State management for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [showReview, setShowReview] = useState(false);

  // Validation helpers
  const isValidEmail = (emailValue: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(emailValue);
  };

  const nameError = name.trim() === '' ? 'Name is required' : '';
  const emailError = email.trim() === '' ? 'Email is required' : !isValidEmail(email) ? 'Please enter a valid email' : '';

  const isStep1Valid = name.trim() !== '' && email.trim() !== '' && isValidEmail(email);
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = true; // Features selection is optional

  // Handle Next button
  const handleNext = () => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !isStep2Valid) return;
    if (currentStep === 3 && !isStep3Valid) return;
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  };

  // Handle Back button
  const handleBack = () => {
    if (showReview) {
      setShowReview(false);
    } else if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  // Handle Submit
  const handleSubmit = () => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  };

  // Handle feature checkbox toggle
  const toggleFeature = (feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  };

  // Create satisfaction radio options
  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));

  // Determine progress display
  const progressStep = showReview ? 4 : currentStep;
  const progressText = `Step ${progressStep} of 4`;

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-3)" align="center">
          <Heading level={2}>Survey Form</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{progressText}</Text>
        </Stack>

        {/* Progress Bar */}
        <Progress value={progressStep} max={4} size="md" />

        {/* Step 1: Name and Email */}
        {currentStep === 1 && !showReview && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={setName}
                placeholder="Enter your name"
                error={nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                placeholder="you@example.com"
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && !showReview && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && !showReview && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Which features interest you?</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => toggleFeature(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4 (not the actual final step): Comments */}
        {currentStep === 4 && !showReview && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={setComments}
                placeholder="Share any additional feedback (optional)"
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 4: Review */}
        {showReview && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                <Box
                  as={Hoverable}
                  hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                    <Text>{name}</Text>
                  </Stack>
                </Box>
                <Box
                  as={Hoverable}
                  hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                    <Text>{email}</Text>
                  </Stack>
                </Box>
                <Box
                  as={Hoverable}
                  hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction Rating</Text>
                    <Text>{satisfaction && parseInt(satisfaction, 10) > 0 ? `${satisfaction} - ${props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}` : 'Not selected'}</Text>
                  </Stack>
                </Box>
                <Box
                  as={Hoverable}
                  hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features of Interest</Text>
                    <Text>{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                  </Stack>
                </Box>
                <Box
                  as={Hoverable}
                  hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                  padding="var(--ggui-spacing-3)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-md)"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                    <Text>{comments || '(No comments provided)'}</Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1 && !showReview}
          >
            Back
          </Button>
          {!showReview && currentStep < 4 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid) ||
                (currentStep === 3 && !isStep3Valid)
              }
            >
              Next
            </Button>
          )}
          {currentStep === 4 && !showReview && (
            <Button
              variant="primary"
              onClick={handleNext}
            >
              Review
            </Button>
          )}
          {showReview && (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

