                    <Stack gap="var(--ggui-spacing-2)">
                      {/* Task Title */}
                        <Input label="Edit task title" aria-label="Edit task title" value={editTitle} onChange={setEditTitle} placeholder="Task title" />
                        <Button variant="ghost" size="sm" onClick={() => { setEditingId(task.id || ''); setEditTitle(task.title || ''); }}>
                          Edit
                        </Button>

                      {/* Priority Badge */}
                      {task.priority && (
                        <Badge variant={getPriorityVariant(task.priority)} size="sm">
                          {task.priority}
                        </Badge>
                      )}

                      {/* Assignee & Due Date */}
                      <Row gap="var(--ggui-spacing-2)" align="center">
                        {task.assignee && <Avatar name={task.assignee} size="sm" />}
                        {task.dueDate && (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {new Date(task.dueDate).toLocaleDateString()}
                          </Text>
                        )}
                      </Row>

                      {/* Move Dropdown */}
                      <Dropdown
                        trigger={<Button variant="ghost" size="xs" aria-label={`Move task to another column`}>Move</Button>}
                        options={props.columns.filter(c => c.id !== col.id).map(c => ({ value: c.id || '', label: c.name || '' }))}
                        value={col.id || ''}
                        onChange={(newCol) => handleMoveTask(task.id || '', newCol)}
                        placement="bottom-start"
                      />

                      {/* Edit/Save Actions */}
                      {editingId === task.id && (
                        <Row gap="var(--ggui-spacing-1)" justify="between">
                          <Button variant="primary" size="xs" onClick={() => handleEditTask(task.id || '', editTitle)}>Save</Button>
                          <Button variant="ghost" size="xs" onClick={() => { setEditingId(null); setEditTitle(''); }}>Cancel</Button>
                        </Row>
                      )}
                    </Stack>
                  </Card>
                ))}
              </Stack>

              {/* Add Task Button/Form */}
              {addingTaskCol === col.id ? (
                <Card padding="var(--ggui-spacing-3)" border={true} style={{ backgroundColor: 'var(--ggui-color-surfaceVariant)' }}>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Enter task title" />
                    <Select
                      label="Priority"
                      value={newTaskPriority}
                      onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                      options={[
                        { value: 'low', label: 'Low' },
                        { value: 'medium', label: 'Medium' },
                        { value: 'high', label: 'High' },
                      ]}
                    />
                    <Row gap="var(--ggui-spacing-2)" justify="end">
                      <Button variant="primary" size="sm" onClick={() => handleCreateTask(col.id || '')}>Create</Button>
                      <Button variant="ghost" size="sm" onClick={() => { setAddingTaskCol(null); setNewTaskTitle(''); }}>Cancel</Button>
                    </Row>
                  </Stack>
                </Card>
              ) : (
                <Button variant="outline" size="sm" fullWidth onClick={() => setAddingTaskCol(col.id || '')}>
                  + Add Task
                </Button>
              )}
            </Stack>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

