// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements based on search query (name or symbol, case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [searchQuery, props.elements]);

  // Category color mapping (design tokens)
  const categoryColors: Record<string, string> = {
    'noble-gas': 'var(--ggui-color-primary-500)',
    'alkali-metal': 'var(--ggui-color-success-500)',
    'alkaline-earth-metal': 'var(--ggui-color-info-500)',
    'transition-metal': 'var(--ggui-color-warning-500)',
    'post-transition-metal': 'var(--ggui-color-error-500)',
    'nonmetal': 'var(--ggui-color-primary-300)',
    'halogen': 'var(--ggui-color-warning-300)',
    'lanthanide': 'var(--ggui-color-primary-200)',
    'actinide': 'var(--ggui-color-error-200)',
    'metalloid': 'var(--ggui-color-secondary-400)',
  };

  const getCategoryColor = (category?: string) => {
    if (!category) return 'var(--ggui-color-surfaceVariant)';
    return categoryColors[category.toLowerCase()] || 'var(--ggui-color-surfaceVariant)';
  };

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map((el) => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  return (
    <Container maxWidth="7xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Interactive periodic table. Click on any element to view details.
          </Text>
        </Stack>

        {/* Search Input */}
        <Input
          label="Search elements"
          placeholder="Search by name or symbol (e.g., Gold, Au)..."
          value={searchQuery}
          onChange={setSearchQuery}
          type="search"
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" weight="semibold">Category Legend</Text>
            <Box display="flex" flexWrap="wrap" gap="var(--ggui-spacing-3)">
              {categories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    width="20px"
                    height="20px"
                    background={getCategoryColor(category)}
                    borderRadius="var(--ggui-shape-radius-sm)"
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Box>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          display="grid"
          gridTemplateColumns="repeat(18, 1fr)"
          gap="var(--ggui-spacing-1)"
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-surface)"
          borderRadius="var(--ggui-shape-radius-md)"
          border="1px solid var(--ggui-color-outline)"
        >
          {filteredElements.map((element) => {
            const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
            const bgColor = getCategoryColor(element.category);

            return (
              <Card
                key={element.atomicNumber || Math.random()}
                as={Clickable}
                onClick={() => setSelectedElement(element)}
                padding="var(--ggui-spacing-2)"
                shadow="sm"
                background={bgColor}
                style={{
                  gridRow: element.row || 'auto',
                  gridColumn: element.col || 'auto',
                  cursor: 'pointer',
                  border: isSelected ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                  transition: 'all 200ms ease',
                  opacity: filteredElements.includes(element) ? 1 : 0.3,
                }}
                hoverStyle={{
                  opacity: 0.9,
                  boxShadow: 'var(--ggui-shape-shadow-md)',
                }}
              >
                <Stack gap="var(--ggui-spacing-1)" align="center" justify="center">
                  {/* Atomic Number (top-left) */}
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant)"
                    size="xs"
                    align="left"
                    style={{ alignSelf: 'flex-start' }}
                  >
                    {element.atomicNumber}
                  </Text>

                  {/* Symbol (large, centered) */}
                  <Text
                    variant="overline"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface)"
                    align="center"
                  >
                    {element.symbol}
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-4)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Row justify="between" align="center">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  ✕ Close
                </Button>
              </Row>

              <Divider />

              <Row gap="var(--ggui-spacing-6)" wrap>
                <Stack gap="var(--ggui-spacing-3)" style={{ flex: '1', minWidth: '200px' }}>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Symbol
                    </Text>
                    <Text variant="body" weight="semibold" size="lg">
                      {selectedElement.symbol}
                    </Text>
                  </Box>

                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Number
                    </Text>
                    <Text variant="body" weight="semibold" size="lg">
                      {selectedElement.atomicNumber}
                    </Text>
                  </Box>
                </Stack>

                <Stack gap="var(--ggui-spacing-3)" style={{ flex: '1', minWidth: '200px' }}>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Weight
                    </Text>
                    <Text variant="body" weight="semibold" size="lg">
                      {selectedElement.atomicWeight?.toFixed(2)}
                    </Text>
                  </Box>

                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Category
                    </Text>
                    <Badge
                      variant="primary"
                      size="md"
                      style={{ background: getCategoryColor(selectedElement.category) }}
                    >
                      {selectedElement.category || 'Unknown'}
                    </Badge>
                  </Box>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

