import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Derived values
  const isOutOfStock = !props.product.stock || props.product.stock === 0;
  const isLowStock = props.product.stock && props.product.stock > 0 && props.product.stock <= 5;
  const maxQuantity = props.product.stock || 1;
  const priceFormatted = props.product.price !== undefined && props.product.currency
    ? `${props.product.currency}${props.product.price.toFixed(2)}`
    : 'N/A';

  // Handlers
  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity((prev) => {
      const newQty = Math.max(1, Math.min(maxQuantity, prev + delta));
      return newQty;
    });
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (!isOutOfStock && props.product.id) {
      addToCart({ productId: props.product.id, quantity });
      setQuantity(1); // Reset quantity after adding
    }
  }, [quantity, isOutOfStock, props.product.id, addToCart]);

  // Rating stars renderer
  const renderRatingStars = (rating: number | undefined) => {
    if (rating === undefined) return null;
    const stars = Array.from({ length: 5 }, (_, i) => {
      const isFilled = i < Math.floor(rating);
      return (
        <Icon
          key={i}
          name={isFilled ? 'star' : 'star'}
          size={20}
          color={isFilled ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      );
    });
    return <Row gap="var(--ggui-spacing-1)" align="center">{stars}</Row>;
  };

  // Tab items
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text variant="body" color="var(--ggui-color-onSurface)" style={{ whiteSpace: 'pre-wrap' }}>
          {props.product.description || 'No description available'}
        </Text>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Stack gap="var(--ggui-spacing-3)" style={{ width: '100%' }}>
          {Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
            <Table
              columns={[
                { key: 'key', header: 'Property', render: (v) => <Text variant="body">{v as string}</Text> },
                { key: 'value', header: 'Value', render: (v) => <Text variant="body">{v as string}</Text> },
              ]}
              data={props.product.specifications.map((spec: any) => ({
                key: spec.key || spec.name || 'unknown',
                value: spec.value || 'N/A',
              }))}
            />
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              No specifications available
            </Text>
          )}
        </Stack>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-4)" style={{ width: '100%' }}>
          {Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
            props.product.reviews.map((review: any, idx: number) => (
              <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm" border>
                <Stack gap="var(--ggui-spacing-2)">
                  <Row gap="var(--ggui-spacing-3)" align="center" justify="between">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label" color="var(--ggui-color-onSurface)" weight="semibold">
                        {review.author || 'Anonymous'}
                      </Text>
                      <Row gap="var(--ggui-spacing-1)" align="center">
                        {renderRatingStars(review.rating)}
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                          {review.rating || 0}/5
                        </Text>
                      </Row>
                    </Stack>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                      {review.date
                        ? new Date(review.date).toLocaleDateString()
                        : new Date().toLocaleDateString()}
                    </Text>
                  </Row>
                  <Text variant="body" color="var(--ggui-color-onSurface)">
                    {review.text || 'No review text'}
                  </Text>
                </Stack>
              </Card>
            ))
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              No reviews yet
            </Text>
          )}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* TOP SECTION: Image, Title, Price, Rating, Stock */}
        <Stack gap="var(--ggui-spacing-6)" direction="horizontal" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            padding="var(--ggui-spacing-12)"
            background="var(--ggui-color-primary-50)"
            borderRadius="var(--ggui-shape-radius-lg)"
            style={{ flex: '1 1 400px', minHeight: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack align="center" justify="center" gap="var(--ggui-spacing-4)">
              <Icon name="image" size={80} color="var(--ggui-color-primary-200)" />
              <Text variant="label" color="var(--ggui-color-primary-700)" align="center">
                {props.product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-6)" style={{ flex: '1 1 350px' }}>
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={1} color="var(--ggui-color-onSurface)">
                {props.product.name || 'Product Name'}
              </Heading>
              <Heading level={3} color="var(--ggui-color-primary-600)">
                {priceFormatted}
              </Heading>
            </Stack>

            {/* Rating Stars */}
            <Stack gap="var(--ggui-spacing-2)" align="start">
              {renderRatingStars(props.product.rating)}
              {props.product.rating !== undefined && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="sm">
                  {props.product.rating.toFixed(1)} out of 5 stars
                  {props.product.reviewCount ? ` (${props.product.reviewCount} reviews)` : ''}
                </Text>
              )}
            </Stack>

            {/* Stock Status Badge */}
            <Stack gap="var(--ggui-spacing-2)" align="start">
              {isOutOfStock ? (
                <Badge variant="error" size="md">
                  Out of Stock
                </Badge>
              ) : isLowStock ? (
                <Badge variant="warning" size="md">
                  Low Stock ({props.product.stock})
                </Badge>
              ) : (
                <Badge variant="success" size="md">
                  In Stock
                </Badge>
              )}
            </Stack>
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Stack gap="var(--ggui-spacing-4)">
          <Tabs
            variant="line"
            items={tabItems}
            activeKey={activeTab}
            onChange={setActiveTab}
            size="md"
          />
        </Stack>

        {/* BOTTOM SECTION: Quantity & Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md" border>
          <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center" justify="start" wrap>
            {/* Quantity Selector */}
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Text variant="label" color="var(--ggui-color-onSurface)" weight="medium">
                Quantity
              </Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(-1)}
                  disabled={quantity <= 1}
                >
                  <Icon name="minus" size={16} />
                </Button>
                <Box
                  padding="0 var(--ggui-spacing-3)"
                  style={{
                    minWidth: '48px',
                    textAlign: 'center',
                    borderRadius: 'var(--ggui-shape-radius-md)',
                    border: '1px solid var(--ggui-color-outline)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="medium">
                    {quantity}
                  </Text>
                </Box>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(1)}
                  disabled={quantity >= maxQuantity}
                >
                  <Icon name="plus" size={16} />
                </Button>
              </Row>
            </Stack>

            <Spacer size="flex" />

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={isOutOfStock}
              fullWidth={false}
              leftIcon={<Icon name="shopping-cart" size={20} />}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

