/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // Local state for UI
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, []);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
      scrollToBottom();
    }
  }, [message.latest, scrollToBottom]);

  // Get current typing indicator
  const isTyping = typing.latest?.active ?? false;
  const typingSender = typing.latest?.sender;

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      const payload: ActionSendMessagePayload = {
        text: inputText,
        timestamp: new Date().toISOString(),
      };
      sendMessage(payload);
      setInputText('');
      scrollToBottom();
    }
  }, [inputText, sendMessage, scrollToBottom]);

  // Handle Enter key to send (Shift+Enter for newline)
  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // Format timestamp for display
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-0)">
      <Stack direction="vertical" gap="0" align="stretch" style={{ height: '100vh' }}>
        {/* Header */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)" style={{ borderBottom: `1px solid var(--ggui-color-outlineVariant)` }}>
          <Row justify="between" align="center" style={{ gap: 'var(--ggui-spacing-3)' }}>
            <Stack direction="vertical" gap="var(--ggui-spacing-1)">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
            </Stack>
            <Badge variant="primary" size="md">{props.participantCount} {props.participantCount === 1 ? 'participant' : 'participants'}</Badge>
          </Row>
        </Box>

        {/* Message List */}
        <Stack direction="vertical" gap="var(--ggui-spacing-3)" align="stretch" style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }} role="region" aria-label="Chat messages">
          {allMessages && allMessages.length > 0 ? (
            allMessages.map((msg, idx) => {
              const isCurrentUser = msg.sender === props.currentUser;
              const prevMsg = idx > 0 ? allMessages[idx - 1] : null;
              const showAvatar = !prevMsg || prevMsg.sender !== msg.sender;
              const nextMsg = idx < allMessages.length - 1 ? allMessages[idx + 1] : null;
              const isLastInGroup = !nextMsg || nextMsg.sender !== msg.sender;

              return (
                <Box key={idx} role="article">
                  <Row
                    justify={isCurrentUser ? 'end' : 'start'}
                    align="end"
                    style={{ gap: 'var(--ggui-spacing-2)' }}
                  >
                    {!isCurrentUser && showAvatar && (
                      <Avatar
                        name={msg.sender || 'User'}
                        size="sm"
                        shape="circle"
                         style={{ flexShrink: 0 }}
                      />
                    )}
                    {!isCurrentUser && !showAvatar && <div style={{ width: 'var(--ggui-spacing-8)', flexShrink: 0 }} aria-hidden="true" />}

                    <Stack
                      direction="vertical"
                      gap="var(--ggui-spacing-1)"
                      align={isCurrentUser ? 'end' : 'start'}
                      style={{ maxWidth: '60%' }}
                    >
                      {showAvatar && (
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                          {msg.sender || 'User'}
                        </Text>
                      )}
                      <Box
                        padding="var(--ggui-spacing-3)"
                        background={
                          isCurrentUser
                            ? 'var(--ggui-color-primary-600)'
                            : 'var(--ggui-color-surfaceVariant)'
                        }
                        borderRadius="var(--ggui-shape-radius-lg)"
                        style={{ wordWrap: 'break-word' }}
                      >
                        <Text
                          color={
                            isCurrentUser
                              ? 'var(--ggui-color-onContainer)'
                              : 'var(--ggui-color-onSurface)'
                          }
                          variant="body"
                        >
                          {msg.text}
                        </Text>
                      </Box>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant)"
                        size="xs"
                      >
                        {formatTime(msg.timestamp)}
                      </Text>
                    </Stack>

                    {isCurrentUser && <div style={{ width: 'var(--ggui-spacing-8)', flexShrink: 0 }} aria-hidden="true" />}
                  </Row>
                </Box>
              );
            })
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant)" align="center" style={{ marginTop: 'var(--ggui-spacing-6)' }}>
              No messages yet. Start the conversation!
            </Text>
          )}

           {/* Typing Indicator */}
           {isTyping && typingSender && (
             <Card padding="var(--ggui-spacing-3)" shadow="sm" aria-live="polite">
               <Row align="center" style={{ gap: 'var(--ggui-spacing-2)' }}>
                 <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" is="span">
                   {typingSender} is typing
                 </Text>
                 <Spinner size={16} color="var(--ggui-color-primary-600)" />
               </Row>
             </Card>
           )}

          <div ref={messagesEndRef} />
        </Stack>

        {/* Input Area */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)" style={{ borderTop: `1px solid var(--ggui-color-outlineVariant)` }}>
          <Row align="end" style={{ gap: 'var(--ggui-spacing-2)' }}>
            <TextArea
              label="Message"
              placeholder="Type a message..."
              value={inputText}
              onChange={setInputText}
              onKeyDown={handleKeyDown}
              rows={2}
              style={{ flex: 1 }}
            />
            <Button
              variant="primary"
              size="md"
              onClick={handleSendMessage}
              disabled={!inputText.trim()}
              rightIcon={<Icon name="send" size={18} />}
            >
              Send
            </Button>
          </Row>
        </Box>
      </Stack>
    </Container>
  );
}

