// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  // State: merge initial stocks with live updates
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());

  // Merge price updates into display stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const updated = priceUpdate.latest;
      setDisplayStocks((prev) => {
        const newStocks = prev.map((stock) =>
          stock.symbol === updated.symbol
            ? {
                ...stock,
                price: updated.price ?? stock.price,
                change: updated.change ?? stock.change,
                changePercent: updated.changePercent ?? stock.changePercent,
              }
            : stock
        );
        return newStocks;
      });

      // Highlight the updated symbol briefly
      if (updated.symbol) {
        setHighlightedSymbols((prev) => new Set([...prev, updated.symbol]));
        setTimeout(() => {
          setHighlightedSymbols((prev) => {
            const next = new Set(prev);
            next.delete(updated.symbol!);
            return next;
          });
        }, 1000);
      }

      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  // Format price with 2 decimals
  const formatPrice = (price?: number): string => {
    if (price === undefined) return 'N/A';
    return `$${price.toFixed(2)}`;
  };

  // Format change percentage
  const formatChangePercent = (changePercent?: number): string => {
    if (changePercent === undefined) return '0.00%';
    return `${Math.abs(changePercent).toFixed(2)}%`;
  };

  // Get color based on change direction
  const getChangeColor = (changePercent?: number): string => {
    if (changePercent === undefined || changePercent === 0) return 'var(--ggui-color-onSurface)';
    return changePercent > 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  };

  // Get border color based on change direction
  const getChangeBorderColor = (changePercent?: number): string => {
    if (changePercent === undefined || changePercent === 0) return 'var(--ggui-color-outline)';
    return changePercent > 0 ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  };

  // Get arrow icon based on change direction
  const getArrowIcon = (changePercent?: number): string => {
    if (changePercent === undefined || changePercent === 0) return '';
    return changePercent > 0 ? '▲' : '▼';
  };

  // Format last updated time
  const formatLastUpdated = (): string => {
    return lastUpdated.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and last updated timestamp */}
        <Box>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {formatLastUpdated()}
            </Text>
          </Stack>
        </Box>

        {/* Stock cards grid - responsive: 3 per row on desktop, 1 on mobile */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
          }}
        >
          {displayStocks.map((stock) => {
            const changePercent = stock.changePercent ?? 0;
            const isHighlighted = highlightedSymbols.has(stock.symbol || '');
            const borderColor = getChangeBorderColor(changePercent);
            const changeColor = getChangeColor(changePercent);
            const arrowIcon = getArrowIcon(changePercent);

            return (
              <Card
                key={stock.symbol}
                padding="var(--ggui-spacing-4)"
                shadow="md"
                border={true}
                radius="lg"
                style={{
                  borderColor: borderColor,
                  borderWidth: '1px',
                  borderStyle: 'solid',
                  animation: isHighlighted ? 'ggui-fadeIn 0.3s ease-out' : 'none',
                  transition: 'all 0.3s ease-in-out',
                  backgroundColor: isHighlighted
                    ? changePercent > 0
                      ? 'var(--ggui-color-success-50)'
                      : 'var(--ggui-color-error-50)'
                    : 'var(--ggui-color-surface)',
                }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Ticker symbol - large and bold */}
                  <Heading level={2} color="var(--ggui-color-onSurface)">
                    {stock.symbol || 'N/A'}
                  </Heading>

                  {/* Company name */}
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                    {stock.name || 'Unknown Company'}
                  </Text>

                  {/* Divider */}
                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Price - formatted with 2 decimals */}
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Current Price
                    </Text>
                    <Text
                      variant="bodyLarge"
                      weight="bold"
                      color="var(--ggui-color-onSurface)"
                      style={{ marginTop: 'var(--ggui-spacing-1)' }}
                    >
                      {formatPrice(stock.price)}
                    </Text>
                  </Box>

                  {/* Change amount and percentage with arrow and color coding */}
                  <Box
                    padding="var(--ggui-spacing-2)"
                    background={changePercent > 0 ? 'var(--ggui-color-success-50)' : changePercent < 0 ? 'var(--ggui-color-error-50)' : 'var(--ggui-color-surfaceVariant)'}
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Row gap="var(--ggui-spacing-2)" align="center">
                      <Text
                        variant="body"
                        weight="semibold"
                        color={changeColor}
                      >
                        {stock.change !== undefined ? (stock.change >= 0 ? '+' : '') + stock.change.toFixed(2) : '0.00'}
                      </Text>
                      <Text
                        variant="body"
                        weight="semibold"
                        color={changeColor}
                        style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1)' }}
                      >
                        {arrowIcon} {formatChangePercent(changePercent)}
                      </Text>
                    </Row>
                  </Box>
                </Stack>
              </Card>
            );
          })}
        </Box>

        {/* Market status indicator */}
        {marketStatus.latest && (
          <Alert
            variant={
              marketStatus.latest.status === 'open'
                ? 'success'
                : marketStatus.latest.status === 'closed'
                  ? 'info'
                  : 'warning'
            }
            title="Market Status"
          >
            Market is currently {marketStatus.latest.status || 'unknown'}.{' '}
            {marketStatus.latest.timestamp && `,updated at ${marketStatus.latest.timestamp}`}
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

