  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State for 3-step wizard
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions[0] || ''),
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications !== undefined ? props.initialProfile.emailNotifications : true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  // Helper: validate email format
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Helper: validate step 1 fields
  const validateStep1 = (): boolean => {
    const newErrors: { name?: string; email?: string } = {};
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!isValidEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Handler: update form field
  const handleFieldChange = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    // Clear error for this field when user starts editing
    if (errors[field as keyof typeof errors]) {
      setErrors((prev) => {
        const next = { ...prev };
        delete next[field as keyof typeof next];
        return next;
      });
    }
  };

  // Handler: next step
  const handleNext = () => {
    if (currentStep === 1) {
      if (!validateStep1()) {
        return;
      }
    }
    setCurrentStep((prev) => Math.min(prev + 1, 3));
  };

  // Handler: previous step
  const handleBack = () => {
    setCurrentStep((prev) => Math.max(prev - 1, 1));
  };

  // Handler: complete onboarding
  const handleComplete = () => {
    if (validateStep1()) {
      complete({
        name: formData.name,
        email: formData.email,
        avatar: formData.avatar,
        role: formData.role,
        emailNotifications: formData.emailNotifications,
        theme: formData.theme,
      });
    }
  };

  // Compute whether Next button should be enabled
  const isNextDisabled = currentStep === 1 && (!formData.name.trim() || !formData.email.trim() || !isValidEmail(formData.email));

  // Render step indicator and progress bar
  const renderStepIndicator = () => (
    <Stack gap="var(--ggui-spacing-4)" align="center">
      <Row gap="var(--ggui-spacing-3)" justify="center" align="center">
        {[1, 2, 3].map((step) => (
          <React.Fragment key={step}>
            <Box
              padding="var(--ggui-spacing-2)"
              borderRadius="var(--ggui-shape-radius-full)"
              background={currentStep >= step ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)'}
            >
              <Text
                variant="label"
                color={currentStep >= step ? 'white' : 'var(--ggui-color-onSurfaceVariant)'}
                align="center"
                weight="bold"
              >
                {step}
              </Text>
            </Box>
            {step < 3 && (
              <Box
                background={currentStep > step ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outlineVariant)'}
                borderRadius="var(--ggui-shape-radius-sm)"
                style={{ width: '40px', height: '4px' }}  
              />
            )}
          </React.Fragment>
        ))}
      </Row>
      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
        Step {currentStep} of 3
      </Text>
    </Stack>
  );

  // Render Step 1: Profile Setup
  const renderStep1 = () => (
    <Stack gap="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-2)">
        <Heading level={3}>Profile Setup</Heading>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          Let's start by setting up your profile information.
        </Text>
      </Stack>

      <Stack gap="var(--ggui-spacing-4)">
        {/* Name Input */}
        <Input
          label="Full Name"
          placeholder="John Doe"
          value={formData.name}
          onChange={(value) => handleFieldChange('name', value)}
          error={errors.name}
          required
        />

        {/* Email Input */}
        <Input
          label="Email Address"
          type="email"
          placeholder="john@example.com"
          value={formData.email}
          onChange={(value) => handleFieldChange('email', value)}
          error={errors.email}
          required
        />

        {/* Avatar Selection */}
        <FormField label="Avatar" required>
          <Row gap="var(--ggui-spacing-3)" wrap>
            {props.avatarOptions.map((avatar) => (
              <Box
                key={avatar}
                as={Clickable}
                onClick={() => handleFieldChange('avatar', avatar)}
                padding="var(--ggui-spacing-2)"
                borderRadius="var(--ggui-shape-radius-md)"
                background={formData.avatar === avatar ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                style={{ border: formData.avatar === avatar ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent', cursor: 'pointer', transition: 'all 200ms ease' }}
              >
                <Text size="3xl">{avatar}</Text>
              </Box>
            ))}
        </FormField>
      </Stack>
    </Stack>
  );

  // Render Step 2: Preferences
  const renderStep2 = () => (
    <Stack gap="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-2)">
        <Heading level={3}>Preferences</Heading>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          Customize your preferences to tailor your experience.
        </Text>
      </Stack>

      <Stack gap="var(--ggui-spacing-4)">
        {/* Role Selection */}
        <Select
          label="Role"
          value={formData.role}
          onChange={(value) => handleFieldChange('role', value)}
          options={props.roleOptions.map((role) => ({
            value: role.toLowerCase(),
            label: role,
          }))}        
          placeholder="Select your role"
        />

        {/* Email Notifications Toggle */}
        <Toggle
          label="Email Notifications"
          checked={formData.emailNotifications}
          onChange={(checked) => handleFieldChange('emailNotifications', checked)}
        />

        {/* Theme Preference Toggle */}
        <Box>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Theme Preference        
          </Text>
          <Row gap="var(--ggui-spacing-2)" align="center" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
            <Button
              variant={formData.theme === 'light' ? 'primary' : 'outline'}
              size="sm"
              onClick={() => handleFieldChange('theme', 'light')}        
            >
              Light
            </Button>
            <Button
              variant={formData.theme === 'dark' ? 'primary' : 'outline'}
              size="sm"
              onClick={() => handleFieldChange('theme', 'dark')}        
            >
              Dark
            </Button>        
          </Row>        
        </Box>
      </Stack>
    </Stack>
  );

  // Render Step 3: Review & Confirm
  const renderStep3 = () => (
    <Stack gap="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-2)">
        <Heading level={3}>Review & Confirm</Heading>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          Please review your information before completing setup.
        </Text>
      </Stack>

      <Card padding="var(--ggui-spacing-4)" shadow="md">
        <Stack gap="var(--ggui-spacing-4)">
          {/* Profile Section */}
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4} color="var(--ggui-color-primary-600)">
              Profile
            </Heading>
            <Divider />
            <Row gap="var(--ggui-spacing-4)" align="start">
              <Box>
                <Text size="4xl">{formData.avatar}</Text>
              </Box>
              <Stack gap="var(--ggui-spacing-2)">
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Name
                  </Text>
                  <Text variant="body">{formData.name}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Email
                  </Text>
                  <Text variant="body">{formData.email}</Text>
                </Box>
              </Stack>
            </Row>
          </Stack>

          {/* Preferences Section */}
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4} color="var(--ggui-color-primary-600)">
              Preferences
            </Heading>
            <Divider />
            <Stack gap="var(--ggui-spacing-2)">
              <Row justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Role
                </Text>
                <Badge variant="primary">
                  {props.roleOptions.find((r) => r.toLowerCase() === formData.role) || formData.role}        
                </Badge>
              </Row>
              <Row justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Email Notifications
                </Text>
                <Badge variant={formData.emailNotifications ? 'success' : 'default'}>
                  {formData.emailNotifications ? 'Enabled' : 'Disabled'}        
                </Badge>
              </Row>
              <Row justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Theme
                </Text>
                <Badge variant={formData.theme === 'dark' ? 'secondary' : 'default'}>
                  {formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}        
                </Badge>
              </Row>
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Stack>
  );

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Step Indicator */}
        {renderStepIndicator()}

        {/* Step Content */}
        <Box
          padding="var(--ggui-spacing-6)"
          background="var(--ggui-color-surface)"
          borderRadius="var(--ggui-shape-radius-lg)"
          style={{ border: '1px solid var(--ggui-color-outlineVariant)' }}
        >
          {currentStep === 1 && renderStep1()}
          {currentStep === 2 && renderStep2()}
          {currentStep === 3 && renderStep3()}
        </Box>

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}            
            disabled={currentStep === 1}        
          >
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {currentStep < 3 && (
              <Button
                variant="primary"
                onClick={handleNext}            
                disabled={isNextDisabled}        
              >
                Next
              </Button>
            )}
            {currentStep === 3 && (
              <Button
                variant="primary"
                onClick={handleComplete}        
              >
                Complete Setup
              </Button>
            )}
          </Row>        
        </Row>
      </Stack>
    </Container>
  );
}
